/**
 * Consumption-`Package.swift` generation. The `render*` functions are PURE
 * (inputs → manifest string) so the generated bytes are unit-testable; the
 * `emit*` functions are thin wrappers that add the filesystem side effects
 * (mkdir, `root` symlink, write) and return the RN dependency contributions.
 */

'use strict';

const fs = require('fs');
const path = require('path');
const { reactProductDependencies, reactPackageDeclarations } = require('./react-descriptor');
const { runDumpPackage } = require('./cli');

// ---------------------------------------------------------------------------
// Pure: parse `swift package dump-package` JSON → { name, products, targets }
// ---------------------------------------------------------------------------

/** Keep only regular targets and library products; resolve same-package sibling deps by name. */
function parseDumpedManifest(json) {
  const pkg = JSON.parse(json);
  const targets = (pkg.targets ?? [])
    .filter((t) => t.type === 'regular')
    .map((t) => ({
      name: t.name,
      path: t.path,
      publicHeadersPath: t.publicHeadersPath ?? null,
      // sibling targets referenced by name within this same package
      siblingDeps: (t.dependencies ?? []).map((d) => d.byName?.[0]).filter(Boolean),
    }));
  const regularNames = new Set(targets.map((t) => t.name));
  const products = (pkg.products ?? [])
    .filter((p) => Object.keys(p.type ?? {})[0] === 'library')
    .map((p) => ({ name: p.name, targets: (p.targets ?? []).filter((n) => regularNames.has(n)) }))
    .filter((p) => p.targets.length);
  return { name: pkg.name, products, targets };
}

// ---------------------------------------------------------------------------
// Pure: render manifest strings
// ---------------------------------------------------------------------------

/** Precompiled: expose the prebuilt xcframework directly as a library product (binaryTarget). */
function renderPrecompiledManifest(product, xcframeworkRelPath) {
  return `// swift-tools-version: 6.0
// AUTO-GENERATED by expo/scripts/spm/plugin.js — do not edit.
// Consumption package for the precompiled ${product}.xcframework.
import PackageDescription

let package = Package(
    name: "${product}",
    platforms: [.iOS(.v15)],
    products: [
        .library(name: "${product}", targets: ["${product}"]),
    ],
    targets: [
        .binaryTarget(name: "${product}", path: "${xcframeworkRelPath}"),
    ]
)
`;
}

/** Source-with-manifest: mirror the parsed targets/products, inject the given deps. */
function renderSourceManifest(manifest, pkgDeps, injected) {
  const targetsSwift = manifest.targets
    .map((t) => {
      const deps = [...t.siblingDeps.map((n) => `"${n}"`), ...injected];
      const headers = t.publicHeadersPath
        ? `\n            publicHeadersPath: "${t.publicHeadersPath}",`
        : '';
      return `        .target(
            name: "${t.name}",
            dependencies: [
                ${deps.join(',\n                ')},
            ],
            path: "root/${t.path}",${headers}
        )`;
    })
    .join(',\n');

  const productsSwift = manifest.products
    .map(
      (p) =>
        `        .library(name: "${p.name}", targets: [${p.targets.map((n) => `"${n}"`).join(', ')}])`
    )
    .join(',\n');

  return `// swift-tools-version: 6.0
// AUTO-GENERATED by expo/scripts/spm/plugin.js — do not edit.
// Source consumption package for "${manifest.name}": mirrors the module's checked-in
// Package.swift targets and injects the React + ExpoModulesCore dependencies.
import PackageDescription

let package = Package(
    name: "${manifest.name}",
    platforms: [.iOS(.v15)],
    products: [
${productsSwift}
    ],
    dependencies: [
        ${pkgDeps.join(',\n        ')},
    ],
    targets: [
${targetsSwift}
    ],
    swiftLanguageModes: [.v5],
    cxxLanguageStandard: .cxx20
)
`;
}

/** Pure-Swift source: single Swift target over the module's `ios`/`apple` sources. */
function renderPureSwiftManifest(product, srcRel, pkgDeps, targetDeps) {
  return `// swift-tools-version: 6.0
// AUTO-GENERATED by expo/scripts/spm/plugin.js — do not edit.
// Pure-Swift source consumption package for "${product}".
import PackageDescription

let package = Package(
    name: "${product}",
    platforms: [.iOS(.v15)],
    products: [
        .library(name: "${product}", targets: ["${product}"]),
    ],
    dependencies: [
        ${pkgDeps.join(',\n        ')},
    ],
    targets: [
        .target(
            name: "${product}",
            dependencies: [
                ${targetDeps.join(',\n                ')},
            ],
            path: "root/${srcRel}"
        ),
    ],
    swiftLanguageModes: [.v5],
    cxxLanguageStandard: .cxx20
)
`;
}

// ---------------------------------------------------------------------------
// I/O: emit a package dir (write manifest + `root` symlink) and return deps
// ---------------------------------------------------------------------------

/** Point a `root` symlink at the real module source so target `path:`s resolve to real files. */
function linkRoot(pkgDir, moduleRoot) {
  const rootLink = path.join(pkgDir, 'root');
  try {
    fs.rmSync(rootLink, { recursive: true, force: true });
  } catch {}
  fs.symlinkSync(moduleRoot, rootLink);
}

/**
 * Point a stable `artifacts/<product>.xcframework` symlink at the flavor-resolved
 * xcframework and return the package-relative path for the binaryTarget. The
 * binaryTarget always references this symlink (never the flavor path directly), so
 * the manifest bytes are flavor-independent and swap-flavor.js can repoint the link
 * per-build. `ln -sfn` semantics: remove any existing link first. Returns
 * "artifacts/<product>.xcframework" (binaryTarget paths must be RELATIVE to the pkg root).
 */
function linkArtifact(pkgDir, product, xcframeworkPath) {
  const artifactsDir = path.join(pkgDir, 'artifacts');
  fs.mkdirSync(artifactsDir, { recursive: true });
  const link = path.join(artifactsDir, `${product}.xcframework`);
  try {
    fs.rmSync(link, { recursive: true, force: true });
  } catch {}
  fs.symlinkSync(xcframeworkPath, link);
  return path.join('artifacts', `${product}.xcframework`);
}

/**
 * Emit a lean CONSUMPTION Package.swift for a precompiled product: expose the
 * prebuilt xcframework directly as a library product. The importable Swift module
 * is the framework's own name (== product), so no wrapper target is needed. React
 * (and anything the binary references) links at the app level. A binaryTarget can't
 * carry dependencies, so this package declares none.
 */
function emitPrecompiledPackage(product, xcframeworkPath, outDir) {
  const pkgDir = path.join(outDir, 'expo-precompiled', product);
  fs.mkdirSync(pkgDir, { recursive: true });
  // The binaryTarget references a stable `artifacts/` symlink rather than the
  // flavor path directly: SwiftPM can't branch a binaryTarget on $CONFIGURATION,
  // so swap-flavor.js repoints this link per-build (Debug⇄Release). SwiftPM
  // requires .binaryTarget(path:) to be RELATIVE to the package root.
  const xcframeworkRelPath = linkArtifact(pkgDir, product, xcframeworkPath);
  fs.writeFileSync(
    path.join(pkgDir, 'Package.swift'),
    renderPrecompiledManifest(product, xcframeworkRelPath)
  );
  return {
    packageDep: { name: product, path: pkgDir },
    productDep: { name: product, package: product },
    artifactLink: path.join(pkgDir, xcframeworkRelPath),
  };
}

/** Injected deps common to both source paths: always ExpoModulesCore, React only when needed. */
function sourceDependencies(react, expoModulesCorePkgDir, needsReact, codegenPkgPath) {
  const wireReact = needsReact && react != null;
  return {
    targetDeps: [
      '.product(name: "ExpoModulesCore", package: "ExpoModulesCore")',
      ...(wireReact ? reactProductDependencies(react) : []),
    ],
    pkgDeps: [
      ...(wireReact ? reactPackageDeclarations(react, codegenPkgPath) : []),
      `.package(name: "ExpoModulesCore", path: "${expoModulesCorePkgDir}")`,
    ],
  };
}

/**
 * Option A: emit a CONSUMPTION Package.swift for a source module that ships a
 * checked-in Package.swift. Re-declares its library targets against the real source
 * (via a `root` symlink) and injects the React product set + ExpoModulesCore — the
 * deps the checked-in manifest deliberately omits. RN owns the merge; the checked-in
 * manifest stays for standalone dev/describe.
 */
function emitSourceManifestPackage(
  moduleRoot,
  react,
  expoModulesCorePkgDir,
  outDir,
  needsReact,
  codegenPkgPath
) {
  const manifest = parseDumpedManifest(runDumpPackage(moduleRoot));
  const pkgDir = path.join(outDir, 'expo-source', manifest.name);
  fs.mkdirSync(pkgDir, { recursive: true });
  linkRoot(pkgDir, moduleRoot);

  const { targetDeps, pkgDeps } = sourceDependencies(
    react,
    expoModulesCorePkgDir,
    needsReact,
    codegenPkgPath
  );
  fs.writeFileSync(
    path.join(pkgDir, 'Package.swift'),
    renderSourceManifest(manifest, pkgDeps, targetDeps)
  );

  return {
    packageDep: { name: manifest.name, path: pkgDir },
    productDeps: manifest.products.map((p) => ({ name: p.name, package: manifest.name })),
  };
}

/**
 * Emit a source consumption package for a module WITHOUT a checked-in Package.swift,
 * from its resolved descriptor. Pure-Swift modules only (single Swift target over the
 * module's `ios` sources). Depends on ExpoModulesCore, plus React iff `needsReact`.
 */
function emitPureSwiftSourcePackage(
  moduleRoot,
  product,
  react,
  expoModulesCorePkgDir,
  outDir,
  needsReact,
  codegenPkgPath
) {
  const srcDir = ['ios', 'apple']
    .map((s) => path.join(moduleRoot, s))
    .find((d) => fs.existsSync(d));
  if (srcDir == null) return null;
  const srcRel = path.relative(moduleRoot, srcDir); // e.g. "ios"
  const pkgDir = path.join(outDir, 'expo-source', product);
  fs.mkdirSync(pkgDir, { recursive: true });
  linkRoot(pkgDir, moduleRoot);

  const { targetDeps, pkgDeps } = sourceDependencies(
    react,
    expoModulesCorePkgDir,
    needsReact,
    codegenPkgPath
  );
  fs.writeFileSync(
    path.join(pkgDir, 'Package.swift'),
    renderPureSwiftManifest(product, srcRel, pkgDeps, targetDeps)
  );

  return {
    packageDep: { name: product, path: pkgDir },
    productDep: { name: product, package: product },
  };
}

module.exports = {
  parseDumpedManifest,
  renderPrecompiledManifest,
  renderSourceManifest,
  renderPureSwiftManifest,
  emitPrecompiledPackage,
  emitSourceManifestPackage,
  emitPureSwiftSourcePackage,
};
